import React from "react";
import ReactDOM from "react-dom/client"; // Utilisez 'react-dom/client' pour React 18
import { BrowserRouter } from "react-router-dom"; // Importez BrowserRouter
import App from "./App";
import './css/main.css';
import "../node_modules/@fortawesome/fontawesome-free/css/all.min.css";

// Utilisez createRoot pour React 18
const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <BrowserRouter> {/* Ajoutez BrowserRouter pour gérer le routage */}
      <App />
    </BrowserRouter>
  </React.StrictMode>
);
